import new_sentry_scope, {capturing} from "@/public/sentry";
import {recordDownload} from "@/public/statistic_g";
import trackEvent from "@/public/statistic";
import {DownloadableInfo, onMessage, sendMessage} from "@/public/messaging";
import {DownloadTask} from "@/public/DownloadTask";
import DownloadOptions = chrome.downloads.DownloadOptions;

class InfoMessage {
    private infoPanel!: HTMLElement;
    private infoText!: HTMLElement;
    private cancelLink!: HTMLElement;
    private shouldClearAfterDownload: boolean = false;
    private static instance: InfoMessage | null = null;

    private constructor() {
        // Private constructor to prevent direct instantiation
    }

    private initialize() {
        this.infoPanel = document.getElementById("infoPanel") as HTMLElement;
        this.infoText = document.getElementById("infoText") as HTMLElement;
        this.cancelLink = document.getElementById("cancel-link") as HTMLElement;
    }

    static getInstance(): InfoMessage {
        if (!InfoMessage.instance) {
            InfoMessage.instance = new InfoMessage();
        }
        return InfoMessage.instance;
    }

    setMessage(message: string, clearAfterDownload: boolean, showCancelLink: boolean = false) {
        this.infoText.innerHTML = message;
        this.infoPanel.style.visibility = "visible";
        this.cancelLink.style.display = showCancelLink ? "inline" : "none";
        this.shouldClearAfterDownload = clearAfterDownload;
    }

    clear() {
        this.infoText.textContent = "";
        this.infoPanel.style.visibility = "hidden";
        this.cancelLink.style.display = "none";
        this.shouldClearAfterDownload = false;
    }

    shouldClearOnDownloadComplete(): boolean {
        return this.shouldClearAfterDownload;
    }
}

// Create a singleton instance but don't initialize it yet
const infoMessage = InfoMessage.getInstance();

async function initializeUI() {
    const sentry_scope = new_sentry_scope();

    // Initialize InfoMessage
    (infoMessage as any).initialize();
    console.log("1. InfoMessage initialized");

    // Initialize user icon
    await initializeUserIcon(sentry_scope);
    console.log("2. User icon initialized");

    // Initialize cancel link
    await initializeCancelLink();
    console.log("3. Cancel link initialized");

    // Initialize loading mode UI
    await initializeLoadingModeUI();
    console.log("4. Loading mode UI initialized");

    // Initialize version display
    printVersion();
    console.log("5. Version display initialized");

    // Initialize message handlers
    await initializeMessageHandlers(sentry_scope);
    console.log("6. Message handlers initialized");

    // Initialize download button
    await initializeDownloadButton(sentry_scope);
    console.log("7. Download button initialized");

    // Initialize rating links
    initializeRatingLinks(sentry_scope);
    console.log("8. Rating links initialized");

    // Initialize warning text and tab listeners
    await initializeWarningSystem(sentry_scope);
    console.log("9. Warning system initialized");

    // Initialize emoji animations
    initializeEmojiAnimations();
    console.log("10. Emoji animations initialized");

    // Initialize thank you message handler
    initializeThankYouMessage(sentry_scope);
    console.log("11. Thank you message handler initialized");

    // Mark initialization as complete
    const marker = document.getElementById('page-initialized-marker');
    if (marker) {
        marker.setAttribute('data-test', 'ready');
    }
    console.log("12. Page initialization complete");
}

async function initializeMessageHandlers(sentry_scope: any) {
    onMessage('dataPrepared', async (message) => {
        await capturing(sentry_scope, undefined, async () => {
            console.log("Panel: Data prepared, initiate downloading...");
            await downloadPreparedData(message.data);
        })
    });

    onMessage('cancel', async (message) => {
        await capturing(sentry_scope, undefined, async () => {
            await cancel(message.data);
        })
    });

    onMessage('infoMessage', async (message) => {
        await capturing(sentry_scope, undefined, async () => {
            await showInfoMessage(message.data);
        })
    });
}

async function initializeDownloadButton(sentry_scope: any) {
    let button = document.getElementById("Download");
    button?.addEventListener("click", async () => {
        await capturing(sentry_scope, undefined, async () => {
            const isMultiPage = document.getElementById('multiPageBtn')?.classList.contains('active') || false;
            console.log("Is multi page:" + isMultiPage)
            await executeDownload(isMultiPage);
        }, async () => {
            await showErrorMessage();
        });
    });
}

function initializeRatingLinks(sentry_scope: any) {
    const links = document.querySelectorAll('a');

    links.forEach(function(link) {
        link.addEventListener('click', function(event) {
            try {
                event.preventDefault();
                const url = this.href;
                chrome.storage.local.set({isRated: true}, function () {
                    console.log('Rated');
                    window.open(url, '_blank');
                });
            } catch (e) {
                sentry_scope.captureException(e);
                console.error(e)
            }
        });
    });
}

document.addEventListener('DOMContentLoaded', async () => {
    console.log('Build Mode: ' + import.meta.env.MODE);
    await initializeUI();
    
    // Initialize share button
    initializeShareButton();
});

async function initializeUserIcon(sentry_scope: any) {
    const userIconLink = document.getElementById("userIconLink") as HTMLAnchorElement;

    try {
        const user = await paywall.getUser();
        if (user.subscriptions && user.subscriptions.length >= 1) {
            userIconLink.style.display = "block";
        }
    } catch (e) {
        sentry_scope.captureException(e);
        console.error("Failed to fetch user subscriptions", e);
    }
}

async function initializeCancelLink() {
    const cancelLink = document.getElementById('cancel-link');
    if (cancelLink) {
        // Replace the <a> tag's href with "#" to prevent navigation
        cancelLink.setAttribute('href', 'javascript:void(0)');
        
        cancelLink.addEventListener('click', async (event) => {
            event.preventDefault(); // Prevent default link behavior
            event.stopPropagation(); // Stop event bubbling
            event.stopImmediatePropagation(); // Stop other handlers
            
            const tabId = await getTabId();
            if (tabId) {
                await sendMessage('cancelLoadingLink', tabId, tabId);
                clearInfoMessage();
                setButtonToDownload();
            }
            
            return false; // Belt and suspenders approach
        }, true); // Use capture phase
    }
}

async function initializeLoadingModeUI() {
    const singlePageBtn = document.getElementById('singlePageBtn') as HTMLButtonElement;
    const multiPageBtn = document.getElementById('multiPageBtn') as HTMLButtonElement;
    const linkDepthContainer = document.getElementById('linkDepthContainer') as HTMLElement;
    const loadingSwitcher = document.getElementById('loadingSwitcher') as HTMLElement;
    const linkDepthInput = document.getElementById('linkDepth') as HTMLInputElement;

    if (singlePageBtn && multiPageBtn && linkDepthContainer && loadingSwitcher && linkDepthInput) {
        // Load saved state
        const { loadingMode, linkDepth } = await chrome.storage.sync.get({
            loadingMode: 'single', // Default to single page
            linkDepth: 1 // Default link depth
        });

        // Apply saved state
        if (loadingMode === 'multi') {
            multiPageBtn.classList.add('active');
            singlePageBtn.classList.remove('active');
            linkDepthContainer.style.display = 'block';
        } else {
            singlePageBtn.classList.add('active');
            multiPageBtn.classList.remove('active');
            linkDepthContainer.style.display = 'none';
        }

        // Set saved link depth
        linkDepthInput.value = linkDepth.toString();

        singlePageBtn.addEventListener('click', async () => {
            singlePageBtn.classList.add('active');
            multiPageBtn.classList.remove('active');
            linkDepthContainer.style.display = 'none';
            await chrome.storage.sync.set({ loadingMode: 'single' });
        });

        multiPageBtn.addEventListener('click', async () => {
            multiPageBtn.classList.add('active');
            singlePageBtn.classList.remove('active');
            linkDepthContainer.style.display = 'block';
            await chrome.storage.sync.set({ loadingMode: 'multi' });
        });

        // Save link depth when it changes
        linkDepthInput.addEventListener('change', async () => {
            await chrome.storage.sync.set({ linkDepth: parseInt(linkDepthInput.value) });
        });
    } else {
        console.error('Toggle buttons or link depth container not found in the DOM.');
    }
}

function printVersion() {
    const version = chrome.runtime.getManifest().version;
    console.log(`Extension Version: ${version}`);
}

// Provided by paywall
declare var paywall: any;

async function executeDownload(isMultiPage: boolean) {
    clearInfoMessage();
    await trackEvent("DownloadStarted")
    await downloadStarted();

    await saveUserInfo();

    try {
        console.log("Opening paywall");
        let res = await paywall.open({ resolveEvent: 'success-purchase' });
        // Paywall status is visible
        console.log('PAY complete ' + res);
        console.log(res);
    } catch (error) {
        console.log("Paywall statis is invisible");
        console.log(error);
        // Paywall status is invisible
    }
    await trackEvent("PaywallPassed")
    console.log("Paywall passed");

    const tabId = await getTabId();
    if (tabId) {
        try {
            await sendMessage('collectHtml', { tabId, isMultiPage }, tabId);
            await trackEvent("SentViaConnection")
        } catch (error: any) {
            if (error.message === "Could not establish connection. Receiving end does not exist.") {
                await askToReloadThePage();
            } else if (error.message === "The page keeping the extension port is moved into back/forward cache, so the message channel is closed.") {
                await askNotToChangeThePage();
            } else {
                throw error; // Re-throw error if it's not the target error
            }
        }
    } else {
        await showErrorMessage();
    }
}

async function saveUserInfo() {
    const ONE_DAY_IN_MS = 24 * 60 * 60 * 1000;

    // Fetch the current user data
    const user = await paywall.getUser();

    // Get previously saved user information from Chrome's local storage
    chrome.storage.local.get(["userInfo", "lastUpdate"], (data) => {
        const { _, lastUpdate } = data;

        const currentTime = Date.now();

        // Check if the data needs to be updated
        if (!lastUpdate || currentTime - lastUpdate >= ONE_DAY_IN_MS) {
            // Save new user information and update the timestamp
            const updatedData = {
                userInfo: user,
                lastUpdate: currentTime,
            };

            chrome.storage.local.set(updatedData, () => {
                console.log("User information updated in local storage.");
            });
        } else {
            console.log("User information is already up to date.");
        }
    });
}

async function resetUserInfo() {
    await chrome.storage.local.remove(["userInfo", "lastUpdate"]);
    console.log("User information and timestamp have been reset.");
}

async function cancel(tabId: number) {
    setButtonToDownload()
    DownloadTask.dispose(tabId);
    await showErrorMessage();
}

function clearInfoMessage() {
    infoMessage.clear();
}

function setInfoMessage(message: string, clearAfterFinishingDownload: boolean, showCancelLink: boolean = false) {
    infoMessage.setMessage(message, clearAfterFinishingDownload, showCancelLink);
}

async function showErrorMessage() {
    await trackEvent("DownloadFailed")
    setInfoMessage("Sorry, something was wrong 💔<br/>Please reload the page.", false, false)
    setButtonToDownload()
}

async function showInfoMessage(message: string) {
    setInfoMessage(message, true, true); // Show cancel link for info messages
}

async function askToReloadThePage() {
    await trackEvent("AskToReloadPage")
    setInfoMessage("👉 Please <a href=\"#\" id=\"reload-link\">reload</a> the page to activate the extension.", false, false)
    const reloadLink = document.getElementById('reload-link');
    reloadLink?.addEventListener('click', async (event) => {
        event.preventDefault(); // Prevent default link behavior
        await sendMessage('reloadCurrentTab', undefined);
        location.reload();      // Reload the current page
    });
    setButtonToDownload()
}

async function askNotToChangeThePage() {
    await trackEvent("askNotToChangeThePage")
    setInfoMessage("👉 Download interrupted.<br>Please do not navigate away from the page.", false, false)
    setButtonToDownload()
}

function setButtonToDownload() {
    let button = document.getElementById("Download") as HTMLButtonElement;
    button.textContent = "Download";
    button.disabled = false;
    button.removeAttribute('data-downloading');
}

async function downloadPreparedData(info: { downloadableInfo: DownloadableInfo | undefined, url: string }) {
    const fobj = info.downloadableInfo?.options;
    const url = info.url
    if (fobj !== undefined) {
        await initiateDownload({info: fobj, url})
        await trackEvent("SuccessDownload", {
            isMultiPage: info.downloadableInfo?.isMultiPage,
            maxDepth: info.downloadableInfo?.maxDepth,
            url: url,
        })
    } else {
        await trackEvent("DownloadObjectMissing", {
            isMultiPage: info.downloadableInfo?.isMultiPage,
            maxDepth: info.downloadableInfo?.maxDepth,
            url: url,
        })
    }
    if (info.downloadableInfo) {
        if (info.downloadableInfo.isMultiPage) {
            await trackEvent("MultiPageDownload", {
                maxDepth: info.downloadableInfo.maxDepth,
                url: url,
            })
        } else {
            await trackEvent("SinglePageDownload")
        }
    }
    if (info.downloadableInfo?.someLinksNotDownloaded) {
        infoMessage.setMessage("Some links were not downloaded because they redirected to other sites.", false, false)
    }
    setButtonToDownload();
    if (infoMessage.shouldClearOnDownloadComplete()) {
        clearInfoMessage();
    }

    // Show the rating container without affecting layout
    let ratingContainer = document.getElementById("ratingContainer") as HTMLElement;
    ratingContainer.style.visibility = "visible";
}

async function initiateDownload(result: { info: DownloadOptions, url: string }) {
    console.log("Panel: Download data ready, initiate downloading...");
    const fobj = result.info;
    chrome.downloads.download(fobj, (res) => {
        if (res === undefined) {
            fobj.filename = "";
            chrome.downloads.download(fobj);
        } else {
            chrome.downloads.onChanged.addListener(async function listener(delta) {
                if (delta.id === res && delta.state && delta.state.current === 'complete') {

                    const short_url = new URL(result.url).origin
                    await recordDownload(result.url, short_url)

                    const {userInfo} = await chrome.storage.local.get(["userInfo"])
                    const version = chrome.runtime.getManifest().version
                    console.log("User info: ")
                    console.log(userInfo)

                    await trackEvent("download", {
                        full_url: result.url,
                        origin: short_url,
                        tier: userInfo.tier,
                        version: version,
                        paid: userInfo.paid || "Unauthorized",
                    })

                    chrome.downloads.onChanged.removeListener(listener)
                }
            })
        }
    });
}

async function downloadStarted() {
    let button = document.getElementById("Download") as HTMLButtonElement;
    button.textContent = "Downloading..."
    button.disabled = true;
    button.setAttribute('data-downloading', 'true');
}

const sentry_scope = new_sentry_scope();

// Periodically check if the extension is pinned
async function monitorPinState() {
    const pinTip = document.getElementById("pin-tip") as HTMLElement;

    setInterval(async () => {
        try {
            let userSettings = await chrome.action.getUserSettings();

            if (userSettings.isOnToolbar) {
                // Hide the tip if the extension is pinned
                pinTip.style.display = "none";
            } else {
                // Show the tip if the extension is not pinned
                pinTip.style.display = "block";
            }
        } catch (e) {
            sentry_scope.captureException(e);
            console.error(e)
        }
    }, 500); // Check every 5 seconds
}

// Start monitoring the pin state
monitorPinState();

function initializeThankYouMessage(sentry_scope: any) {
    const thankYouMessage = document.getElementById("thankYouMessage") as HTMLElement;

    // Function to show the thank-you message and trigger hearts
    function showThankYouMessage() {
        thankYouMessage.style.display = "block";

        // Function to create hearts
        function createHeart() {
            const heart = document.createElement("span");
            heart.className = "heart-emoji";
            heart.textContent = "❤️";

            // Randomize horizontal position
            heart.style.left = `${Math.random() * 100}%`;
            heart.style.position = "absolute";
            heart.style.bottom = "10px";

            thankYouMessage.appendChild(heart);

            // Remove the heart after animation
            setTimeout(() => {
                heart.remove();
            }, 3000);
        }

        // Start heart animation
        setInterval(createHeart, 600); // Adjust frequency here
    }

    window.addEventListener('message', async function (event) {
        try {
            if (
                event.data?.type === 'state' &&
                ['https://onlineapp.pro', 'https://onlineapp.live', 'https://onlineapp.stream'].includes(event.origin)
            ) {
                if (event.data?.state?.visibility_status_reason === "success-payment") {
                    showThankYouMessage()
                    await resetUserInfo()
                }
            }
        } catch (e) {
            sentry_scope.captureException(e);
            console.error(e)
        }
    });
}

function initializeEmojiAnimations() {
    const emojiContainer = document.getElementById("emojiContainer") as HTMLElement;

    // List of cute emojis
    const emojis = ["😊", "🥳", "🔥", "💪"];

    // Function to create and animate an emoji
    function showRandomEmoji() {
        // Randomly select an emoji
        const randomEmoji = emojis[Math.floor(Math.random() * emojis.length)];

        // Create the emoji element
        const emojiElement = document.createElement("span");
        emojiElement.className = "floating-emoji";
        emojiElement.textContent = randomEmoji;

        // Randomize horizontal position slightly around the center
        emojiElement.style.left = `47%`;
        emojiElement.style.bottom = `60%`;

        // Append to container
        emojiContainer.appendChild(emojiElement);

        // Remove emoji after animation ends
        setTimeout(() => {
            emojiElement.remove();
        }, 1000); // Match animation duration
    }

    // Add click handler for emoji animation
    document.getElementById("Download")?.addEventListener("click", showRandomEmoji);
}

async function getTabId(): Promise<number | undefined> {
    const tabs = await chrome.tabs.query({active: true, currentWindow: true});
    return (tabs.length > 0) ? tabs[0].id : undefined;
}

async function initializeWarningSystem(sentry_scope: any) {
    function updateWarningText(url: string | undefined): void {
        const warningContainer = document.getElementById("warningContainer") as HTMLElement;
        const warningText = document.getElementById("warningText") as HTMLElement;
        const downloadButton = document.getElementById("Download") as HTMLButtonElement;
        
        // If download is in progress, don't modify the button state
        if (downloadButton.getAttribute('data-downloading') === 'true') {
            return;
        }

        if (url === undefined || url === "chrome://newtab/" || url === "" || url === "about:blank") {
            warningText.textContent = "";
            warningContainer.style.visibility = "hidden";
            downloadButton.disabled = true;
        } else if (url.includes("youtube.com")) {
            warningText.textContent = "Sorry, I can't download from YouTube 😢";
            warningContainer.style.visibility = "visible";
            downloadButton.disabled = true;
        } else if (url.startsWith("chrome://") && url !== "chrome://newtab/") {
            warningText.textContent = "Sorry, can't download from 'chrome://' 😢";
            warningContainer.style.visibility = "visible";
            downloadButton.disabled = true;
        } else if (url.includes("chromewebstore.google.com")) {
            warningText.textContent = "Sorry, I can't download from Chrome Web Store 😢";
            warningContainer.style.visibility = "visible";
            downloadButton.disabled = true;
        } else {
            warningText.textContent = "";
            warningContainer.style.visibility = "hidden";
            downloadButton.disabled = false;
        }
    }

    // Check the initial active tab URL
    const [tab] = await chrome.tabs.query({ active: true, lastFocusedWindow: true });
    if (tab && tab.url) updateWarningText(tab.url);

    // Listen for tab activation
    chrome.tabs.onActivated.addListener(async (activeInfo) => {
        try {
            const tab = await chrome.tabs.get(activeInfo.tabId);
            if (tab.active) {
                updateWarningText(tab.url);
            }
        } catch (error) {
            sentry_scope.captureException(error);
            console.error(error)
        }
    });

    // Listen for tab updates
    chrome.tabs.onUpdated.addListener(async (tabId, changeInfo, tab) => {
        try {
            if (tab.active) {
                updateWarningText(tab.url);
            }
        } catch (error) {
            sentry_scope.captureException(error);
            console.error(error)
        }
    });
}

// Initialize share button functionality
function initializeShareButton() {
    const shareButton = document.getElementById('shareButton');
    if (shareButton) {
        shareButton.addEventListener('click', async () => {
            const url = 'https://chromewebstore.google.com/detail/website-downloader/iaaokenmfgahhlcfbdipjonlkeinadaa?hl=en';
            
            try {
                await navigator.clipboard.writeText(url);
                // Show temporary feedback
                const shareSpan = shareButton.querySelector('span');
                const originalText = shareSpan?.textContent || 'Share';
                
                if (shareSpan) {
                    shareSpan.textContent = 'Link Copied';
                    setTimeout(() => {
                        shareSpan.textContent = originalText;
                    }, 2000);
                }
                
                console.log('URL copied to clipboard:', url);
            } catch (err) {
                console.error('Failed to copy URL: ', err);
            }
        });
    }
}
